INSERT OR IGNORE INTO library_items (
  id,title,author,item_type,reading_status,cover_url,hd_cover_url,isbn,publisher,
  publication_date,language,series,genres,annotation,read_date,rating,review,quotes,
  acquired_on,purchase_cost_cents,is_sold,sold_on,sale_price_cents,added
)
SELECT
  json_extract(value,'$.id'),json_extract(value,'$.title'),json_extract(value,'$.author'),
  json_extract(value,'$.type'),json_extract(value,'$.status'),json_extract(value,'$.cover'),
  json_extract(value,'$.hdCover'),json_extract(value,'$.isbn'),json_extract(value,'$.publisher'),
  json_extract(value,'$.pubDate'),json_extract(value,'$.language'),json_extract(value,'$.series'),
  json_extract(value,'$.genres'),json_extract(value,'$.annotation'),json_extract(value,'$.read'),
  json_extract(value,'$.rating'),json_extract(value,'$.review'),json_extract(value,'$.quotes'),
  json_extract(value,'$.acquired'),CASE WHEN json_extract(value,'$.cost') IS NULL THEN NULL ELSE round(json_extract(value,'$.cost')*100) END,
  CASE WHEN json_extract(value,'$.sold') THEN 1 ELSE 0 END,json_extract(value,'$.soldDate'),
  CASE WHEN json_extract(value,'$.soldPrice') IS NULL THEN NULL ELSE round(json_extract(value,'$.soldPrice')*100) END,
  json_extract(value,'$.added')
FROM json_each('[{"id":"098959d","title":"Ходячие мертвецы. Том 31. Прогнившее нутро","author":"Роберт Киркман,Чарли Адлард","type":"Комикс","cover":"https://s1.livelib.ru/boocover/1002995914/140/3507/__Hodyachie_mertvetsy._Tom_31._Prognivshee_nutro.jpg","isbn":"978-5-04-102360-7","publisher":"Комильфо","pubDate":"2019","language":"Русский","series":"","genres":["Комиксы","манга","графические романы"],"annotation":"Как мы с вами уже не раз убеждались, Рику Граймсу нелегко даются новые знакомства. Особенно когда речь идёт о поселении, значительно превосходящем его собственное по размеру и численности. Особенно когда им управляет губернатор. Навевает воспоминания, не правда ли? И пока одни, устав от бесконечной борьбы, принимают новую жизнь и её щедрые дары, стараясь влиться в систему и занять своё место в строгой иерархии Содружества, другие не перестают искать подвох. Ведь, как любят повторять наши герои, \"когда что-то слишком хорошо, чтобы быть правдой\"… Дальше вы и сами знаете.","acquired":"","cost":null,"sold":false,"soldDate":"","soldPrice":null,"quotes":[],"status":"Прочитал","read":"2021-12","rating":5,"review":"","added":9999773,"hdCover":""},{"id":"098959c","title":"Ходячие мертвецы. Том 30. Новый мировой порядок","author":"Роберт Киркман,Клифф Ратбёрн,Стефано Гаудиано,Чарли Адлард","type":"Комикс","cover":"https://s1.livelib.ru/boocover/1002946141/140/8198/__Hodyachie_mertvetsy._Tom_30._Novyj_mirovoj_poryadok.jpg","isbn":"978-5-91339-743-0","publisher":"Комильфо","pubDate":"2019","language":"Русский","series":"Ходячие мертвецы","genres":["Комиксы","манга","графические романы"],"annotation":"Наши герои загнаны в угол таинственными людьми в броне. Кто они такие, откуда пришли и почему так хорошо экипированы? Неужели Стефани подставила Юджина, и всё это лишь хитрая уловка, чтобы напасть исподтишка? Быть может, где-то неподалёку есть ещё одно сообщество, о котором они и не догадывались? Новые (и старые) знакомые очень ждут встречи с героями. Но мы-то знаем, опираясь на опыт прошлых встреч, что в мире постапокалипсиса знакомства не всегда проходят гладко. Наших выживших ждёт новый мировой порядок. Но готовы ли они его принять?","acquired":"","cost":null,"sold":false,"soldDate":"","soldPrice":null,"quotes":[],"status":"Прочитал","read":"2021-12","rating":5,"review":"","added":9999772,"hdCover":""},{"id":"098959b","title":"Ходячие мертвецы. Том 29. Какие границы мы переступаем","author":"Роберт Киркман,Чарли Адлард","type":"Комикс","cover":"https://s1.livelib.ru/boocover/1002912131/140/169f/__Hodyachie_mertvetsy._Tom_29._Kakie_granitsy_my_perestupaem.jpg","isbn":"978-5-91339-720-1","publisher":"Комильфо","pubDate":"2018","language":"Русский","series":"","genres":["Комиксы","манга","графические романы"],"annotation":"Том 29: Какие границы мы переступаем — двадцать девятый том комикса «Ходячие мертвецы», включает в себя выпуски 169-174.  Время идёт, и наши герои стараются оправиться после событий 28-го тома. Для одних это стало личной трагедией, а для других — поводом двигаться дальше. Взвесив все за и против, группа решает выйти на связь с таинственной подругой Юджина, что сидит по ту сторону радиоприёмника. Выживая в диком новом мире, они уже много повидали и теперь готовы к проблемам, которые может принести это знакомство. Также в этом томе вы узнаете тайну одного из самых грозных шепчущихся и повстречаете эксцентричную болтливую Принцессу!","acquired":"","cost":null,"sold":false,"soldDate":"","soldPrice":null,"quotes":[],"status":"Прочитал","read":"2021-12","rating":5,"review":"","added":9999771,"hdCover":""},{"id":"098959a","title":"Кофейный дневник","author":"Тамито Аихара","type":"Комикс","cover":"https://s1.livelib.ru/boocover/1006148728/140/2ad5/Tamito_Aihara__Kofejnyj_dnevnik.jpg","isbn":"978-5-7584-0610-6","publisher":"Фабрика комиксов","pubDate":"2021","language":"Русский","series":"","genres":["Комиксы","манга","графические романы"],"annotation":"","acquired":"","cost":null,"sold":false,"soldDate":"","soldPrice":null,"quotes":[],"status":"Прочитал","read":"2021-12","rating":4,"review":"","added":9999770,"hdCover":""}]');

INSERT OR IGNORE INTO library_items (
  id,title,author,item_type,reading_status,cover_url,hd_cover_url,isbn,publisher,
  publication_date,language,series,genres,annotation,read_date,rating,review,quotes,
  acquired_on,purchase_cost_cents,is_sold,sold_on,sale_price_cents,added
)
SELECT
  json_extract(value,'$.id'),json_extract(value,'$.title'),json_extract(value,'$.author'),
  json_extract(value,'$.type'),json_extract(value,'$.status'),json_extract(value,'$.cover'),
  json_extract(value,'$.hdCover'),json_extract(value,'$.isbn'),json_extract(value,'$.publisher'),
  json_extract(value,'$.pubDate'),json_extract(value,'$.language'),json_extract(value,'$.series'),
  json_extract(value,'$.genres'),json_extract(value,'$.annotation'),json_extract(value,'$.read'),
  json_extract(value,'$.rating'),json_extract(value,'$.review'),json_extract(value,'$.quotes'),
  json_extract(value,'$.acquired'),CASE WHEN json_extract(value,'$.cost') IS NULL THEN NULL ELSE round(json_extract(value,'$.cost')*100) END,
  CASE WHEN json_extract(value,'$.sold') THEN 1 ELSE 0 END,json_extract(value,'$.soldDate'),
  CASE WHEN json_extract(value,'$.soldPrice') IS NULL THEN NULL ELSE round(json_extract(value,'$.soldPrice')*100) END,
  json_extract(value,'$.added')
FROM json_each('[{"id":"0989599","title":"Человек-бензопила. Книга 1. Пес и бензопила. Бензопила против нетопыря","author":"Тацуки Фудзимото","type":"Комикс","cover":"https://s1.livelib.ru/boocover/1006818025/140/2040/Tatsuki_Fudzimoto__Chelovekbenzopila._Kniga_1._Pes_i_benzopila._Benzopila_protiv.jpg","isbn":"978-5-389-20205-4","publisher":"Азбука, Азбука-Аттикус","pubDate":"2021","language":"Русский","series":"Графические романы","genres":["Комиксы","манга","графические романы"],"annotation":"Дэндзи – обычный молодой человек, который промышляет охотой на демонов, чтобы расплатиться с долгами покойного отца. Если он хоть раз опоздает с выплатой, его ждет смерть. Дэндзи живет в крошечной лачуге со своим демоническим псом-бензопилой по имени Почита и едва сводит концы с концами. Все о чем он мечтает – ходить на свидания с девушкой и есть хлеб с джемом. Но у судьбы на него другие планы…  В один прекрасный день юноша обретает сверхъестественные силы, позволяющие ему превращать свое тело в живое оружие. Дэндзи вырывается из нищеты и под рев дребезжащих бензопил и крики умирающих демонов начинает прорезать себе дорогу в новую жизнь...","acquired":"","cost":null,"sold":false,"soldDate":"","soldPrice":null,"quotes":[],"status":"Прочитал","read":"2021-12","rating":4.5,"review":"","added":9999769,"hdCover":""},{"id":"0989598","title":"Отель с видом на гавань","author":"Дзиро Танигути,Нацуо Сэкикава","type":"Комикс","cover":"https://s1.livelib.ru/boocover/1006168054/140/a268/__Otel_s_vidom_na_gavan.jpg","isbn":"978-5-7584-0612-0","publisher":"Фабрика комиксов","pubDate":"2021","language":"Русский","series":"","genres":["Комиксы","манга","графические романы"],"annotation":"","acquired":"","cost":null,"sold":false,"soldDate":"","soldPrice":null,"quotes":[],"status":"Прочитал","read":"2021-12","rating":4.5,"review":"","added":9999768,"hdCover":""},{"id":"0989597","title":"Человек-Череп. Том 1","author":"Симамото Кадзухико,Исиномори Сетаро","type":"Комикс","cover":"https://s1.livelib.ru/boocover/1000928136/140/5915/__ChelovekCherep._Tom_1.jpg","isbn":"978-5-7525-2912-2,  978-5-7525-2913-9,  978-4-8899-1702-4","publisher":"Фабрика комиксов","pubDate":"2014","language":"Русский","series":"","genres":["Комиксы","манга","графические романы"],"annotation":"У него забрали семью, лицо и саму душу, но он вернулся из страны мертвых, чтобы отомстить злодеям и заодно узнать, кто наделил его сверхъес­тественными способностями. В сопровождении верного помощника Гаро, в случае опасности трансформирующегося в огромных размеров вол­ка, крокодила и летучую мышь, он идет по следу заказчика убийства своих родителей, но когда достигает цели, правда оказывается слишком ужасной даже для такого хладнокровного и без­душного мстителя, как он. Порвав с прошлым, он начинает бороться против таинственного син­диката, управляющего всем преступным миром страны. он будет защищать людей. Он никогда не остановится. Он будет испепелять врагов адским огнем, что бушует внутри него. Он - Человек-Череп! Довольно непопулярная серия, которая лишь пару раз попадалась мне на глаза. Печально известная своими продажами манга наверняка должна была разочаровать читателя или прийти не по вкусу, но всё это не так. Прочитав первую главу, я понял, что манга обладает очень характерным чувством пафоса 90-ых годов. Действия происходят молниеносно, а читатель находится в предвкушении новых экшн-сцен и раскрытия сюжетных поворотов. Читателя знакомят с событиями ракового дня, изменившего жизнь главного героя и взгляды на мир. На первый взгляд, манга – копия известной всему миру истории о мальчике, потерявшем родителей, но на самом деле общего эти истории практически не имеют. Да, главный герой просыпается в холодном поте по ночам, размышляя о своей утрате, но дальше такие аналогии забываются, и ты не придаёшь им значения. Главная особенность сюжета – это поглощение читателя в круговорот событий, после прочтения очередной главы ты приятно удивлён таким исходом событий и новым клиффхенгером. Хорошо прописанные диалоги создают очень аутентичную атмосферу. Нельзя не отметить и превосходный рисунок. Отличные развороты и кадры поглощают тебя ещё больше в сюжет, приятный симбиоз двух составляющих надолго запомнится.К сожалению, манга не получила своей славы в России, продажи оказались очень слабыми, практически все тома (вышло всего 4) доступны к приобретению, а цена на них очень мала. Также манга отсутсвует в виде сканов, и прочитать продолжение невозможно (в сканах доступен практически весь первый том). Издательство «Фабрика комиксов» неоднократно пыталось возродить выпуск, но всё безрезультатно. После прочтения я сразу же отправился смотреть наличие остальных трёх томов, найдя их в Читай-городе, заказал и с нетерпением жду доставки. Несмотря на незавершённость серии, я готов пожертвовать этим фактом для наслаждения самой историей, надеюсь, что продолжение меня не подведёт. Дебютировав в 2014 году, манга Симамото Кадзухико и Исиномори Сётаро была заморожена, а надежда о продолжении угасает с каждым годом всё больше и больше. Вряд ли возможен выход оставшихся 4-ёх томов, но я настойчиво порекомендую каждому ознакомиться хоть и с небольшой частью манги в сканах или же приобрести несколько томов этой прекрасной истории. Кстати, стоит упомянуть, что манга является продолжением ван-шотной работы Сётаро, которая получила успех среди японских читателей. Человек-череп оказался одной из самых интересных, а с виду невзрачных историй, которые мне довелось читать. Это нисколько не глупое произведение, а вполне себе цельная и гармоничная история, связывающая в себе и паранормальные явления и способности персонажей, а также прекрасную атмосферу самого мира. Еженедельное обсуждение прочитанного в группе ВК                                                Свернуть","acquired":"","cost":null,"sold":false,"soldDate":"","soldPrice":null,"quotes":[],"status":"Прочитал","read":"2021-11","rating":4.5,"review":"","added":9999767,"hdCover":""}]');

INSERT OR IGNORE INTO library_items (
  id,title,author,item_type,reading_status,cover_url,hd_cover_url,isbn,publisher,
  publication_date,language,series,genres,annotation,read_date,rating,review,quotes,
  acquired_on,purchase_cost_cents,is_sold,sold_on,sale_price_cents,added
)
SELECT
  json_extract(value,'$.id'),json_extract(value,'$.title'),json_extract(value,'$.author'),
  json_extract(value,'$.type'),json_extract(value,'$.status'),json_extract(value,'$.cover'),
  json_extract(value,'$.hdCover'),json_extract(value,'$.isbn'),json_extract(value,'$.publisher'),
  json_extract(value,'$.pubDate'),json_extract(value,'$.language'),json_extract(value,'$.series'),
  json_extract(value,'$.genres'),json_extract(value,'$.annotation'),json_extract(value,'$.read'),
  json_extract(value,'$.rating'),json_extract(value,'$.review'),json_extract(value,'$.quotes'),
  json_extract(value,'$.acquired'),CASE WHEN json_extract(value,'$.cost') IS NULL THEN NULL ELSE round(json_extract(value,'$.cost')*100) END,
  CASE WHEN json_extract(value,'$.sold') THEN 1 ELSE 0 END,json_extract(value,'$.soldDate'),
  CASE WHEN json_extract(value,'$.soldPrice') IS NULL THEN NULL ELSE round(json_extract(value,'$.soldPrice')*100) END,
  json_extract(value,'$.added')
FROM json_each('[{"id":"0989596","title":"Приют влюблённого психопата","author":"Маруо Суэхиро","type":"Комикс","cover":"https://s1.livelib.ru/boocover/1006801837/140/c04b/Maruo_Suehiro__Priyut_vlyubljonnogo_psihopata.jpg","isbn":"978-5-7584-0585-7","publisher":"Фабрика комиксов","pubDate":"2021","language":"","series":"","genres":["Комиксы","манга","графические романы"],"annotation":"Манга Суэхиро Маруо, об анонсе переиздания которой я случайно наткнулся в группе издательства. Мне очень понравилось нетривиальное название и загадочно красивая обложка. За время ожидания выхода из печати тома я успел добавить в виш-лист ещё одну работу мангаки – «Шоу уродов господина Араси», рецензию на которую публиковал чуть раньше. И если предыдущая работа, более ранняя, мне показалась без изюминки, но весьма неплохой, то «Приют влюблённого психопата» приятно удивил некоторыми интересными и неожиданными деталями. Манга оказалась не тем, на что я рассчитывал. После прочтения «Шоу уродов господина Араси» мне казалось, что и эта работа окажется цельной историей, затрагивающей определённых героев и обстановку. На самом деле – нет. Том оказался сборником 6 (два сюжета имеют продолжение в виде ещё одной главы) разных историй, написанных с 1988 года по 1993. Размеры у них тоже разные, первая история «Чердачный философ» имеет меньше 10 страниц, но за такой маленький объём, мангака смог ужаснуть читателя непривычным (по меркам гуро жанра) мерзким содержанием. Весь сборник так или иначе связывают эти понятия, ведь каждая история обладает своей мрачностью, вызывающей беспричинное переживание и страх. А вот «Град непротивления» занимает почти половину всего сборника. Главной особенностью конкретно этих историй служит чрезмерное изобилие \"сгущения красок\": казалось бы, что история приятно располагает тебя к героям,но раковой случай или детская травма, раскрывшаяся через несколько лет, может в корне изменить характер героя и твоё отношение к нему. Именно резкую смену стиля повествования, будь то в середине или под конец, помогает сосредоточить рисунок.Это одна из самых красивых работ, говоря широко и затрагивая все истории целиком, которую мне довелось читать. «Шоу уродов господина Араси» (манга вышла в 1984 году) не имела такой притягательности в плане рисунка, когда в данном сборнике показан настоящий триумф мангаки: великолепная ретушь, создающая эффект присутствия перед твоими глазами изображаемого здания или предмета, линии и формы, придающие великолепную анатомию людям. Сюжет, к сожалению или к счастью, отходит на второй план. В сборник включены совершенно разные по характеру повествования истории: японские мифы или последствия участия в войне, ужаснейшее убийство младенца или сумасшествие главного героя, любящего музыку, а может совершенная любовь к своему домашнему питомцу, способному на убийство человека? Думаю, что можно найти хотя бы одну историю на свой вкус. Обращаясь к самому названию – «Приют влюблённого психопата» – отмечу, что в самом сборнике отсутствует история с таким названием. Некий приют или же отель является связующим звеном между некоторыми историями, дебютируя в «Знаток инугами». Данная манга закончилась на одном из самых интересных моментов за весь сборник, у меня были догадки о причинах появления персонажа, но точный ответ получить не удастся. Редакция одного из садомазохистских журналов закрыла проект Маруо, который едва успел закончить работу над 40-ой страницей. Мангака планировал написание трёхсотстраничного романа, но после закрытия у автора пропало желание работать над продолжением. Показательная работа Суэхиро Маруо, прочитав которую, вы можете быть приятно удивлены, если вам не понравилась ранняя работа автора. Несомненный плюс и, возвращаясь к началу рецензии, изюминка манги – это её графическое исполнение. Очень много отличных разворотов и композиций, способных порадовать изощрённых читателей. Второстепенной особенностью является сюжетная составляющая, которая всё также сможет составить палитру ваших чувств и эмоций. После прочтения двух работ Суэхиро Маруо могу смело посоветовать данный сборник для первого ознакомления с автором. В манге присутствуют эрогуро сцены, то есть эпизоды с чрезмерным насилием и эротическими действиями. Еженедельное обсуждение прочитанного в группе ВК                                                Свернуть","acquired":"","cost":null,"sold":false,"soldDate":"","soldPrice":null,"quotes":[],"status":"Прочитал","read":"2021-11","rating":4,"review":"","added":9999766,"hdCover":""},{"id":"0989595","title":"Ходячие мертвецы. Том 28: Верная смерть. Выпуск 167","author":"Роберт Киркман","type":"Книга","cover":"https://s1.livelib.ru/boocover/1003024843/140/affa/Robert_Kirkman__Hodyachie_mertvetsy._Tom_28_Vernaya_smert._Vypusk_167.jpg","isbn":"","publisher":"","pubDate":"2017","language":"Русский, Английский","series":"","genres":[],"annotation":"","acquired":"","cost":null,"sold":false,"soldDate":"","soldPrice":null,"quotes":[],"status":"Прочитал","read":"2021-11","rating":5,"review":"","added":9999765,"hdCover":""}]');

INSERT OR IGNORE INTO library_items (
  id,title,author,item_type,reading_status,cover_url,hd_cover_url,isbn,publisher,
  publication_date,language,series,genres,annotation,read_date,rating,review,quotes,
  acquired_on,purchase_cost_cents,is_sold,sold_on,sale_price_cents,added
)
SELECT
  json_extract(value,'$.id'),json_extract(value,'$.title'),json_extract(value,'$.author'),
  json_extract(value,'$.type'),json_extract(value,'$.status'),json_extract(value,'$.cover'),
  json_extract(value,'$.hdCover'),json_extract(value,'$.isbn'),json_extract(value,'$.publisher'),
  json_extract(value,'$.pubDate'),json_extract(value,'$.language'),json_extract(value,'$.series'),
  json_extract(value,'$.genres'),json_extract(value,'$.annotation'),json_extract(value,'$.read'),
  json_extract(value,'$.rating'),json_extract(value,'$.review'),json_extract(value,'$.quotes'),
  json_extract(value,'$.acquired'),CASE WHEN json_extract(value,'$.cost') IS NULL THEN NULL ELSE round(json_extract(value,'$.cost')*100) END,
  CASE WHEN json_extract(value,'$.sold') THEN 1 ELSE 0 END,json_extract(value,'$.soldDate'),
  CASE WHEN json_extract(value,'$.soldPrice') IS NULL THEN NULL ELSE round(json_extract(value,'$.soldPrice')*100) END,
  json_extract(value,'$.added')
FROM json_each('[{"id":"0989594","title":"Ходячие мертвецы. Том 24. Жизнь и смерть. Выпуск 139","author":"Роберт Киркман","type":"Книга","cover":"https://s1.livelib.ru/boocover/1001130710/140/6b60/Robert_Kirkman__Hodyachie_mertvetsy._Tom_24._Zhizn_i_smert._Vypusk_139.jpg","isbn":"","publisher":"","pubDate":"2015","language":"Русский","series":"","genres":[],"annotation":"Небольшая группа из Королевства пробивается к берегу. Её возглавляет Иезекииль, который развлекается, убивая зомби мечом Мишон. В доке оне встречаются с группой из Александрии, в которую входят Рик, Хит, Аарон и Магна. Рик говорит Иезекиилю, что благодаря производству у них очень много пули и они собираются расчистить побережье от ходячих. Иезекииль намекает на то, что цену на пули нужно снизить, и Рик довольно резко отвечает ему, но затем смягчается.  К берегу подходит парусник. Иезекииль начинает волноваться. На борту судна появляется Мишон. Она холодна к Иезекиилю, зато приветлива с Риком. Пит говорит, что улов был очень удачным. Мишон интересуется, кто такая Магна, и говорит, что ей нравится ходить в море за рыбой, так как в море приходится много работать и нет времени на разные мысли. Она признаётся Рику, что бросила Иезекииля, потому что \"больше не могла так жить\", и рассказывает, что до начала апокалипсиса у неё были дочери, которых она она оставила мужу Доминику, а сама целиком отдалась работе. Теперь они, скорее всего, мертвы, и это гложет её. Поэтому она и ушла от Иезекииля, потому что не считает, что заслуживает счастья. Рик отвечает, что это не так, и просит Мишон вернуться домой.  В Хиллтопе обнаруживается исчезновение Карла. Брианна предполагает, что Карл просто прячется, но Иисус отвечает, что Карл пропустил завтрак и обед. София отмечает, что Карл смелый, поэтому ушёл за стену, а Данте пытается пошутить о том, что Карл ушёл за Лидией, так как она его первая девушка. Мэгги говорит, что из-за поступка Карла у них могут быть очень большие проблемы с Шепчущимися.  Карл сидит в лесу под деревом. К нему подходит Альфа с шепчущимися. Карл объясняет, что следует за ними по своему желанию и его никто не посылал, и что он хочет убедиться, что с Лидией всё хорошо. Хотя он и наставляет пистолет на Альфу, в итоге она предлагает ему присоединиться к шепчущимся.","acquired":"","cost":null,"sold":false,"soldDate":"","soldPrice":null,"quotes":[],"status":"Прочитал","read":"2021-11","rating":5,"review":"","added":9999764,"hdCover":""},{"id":"0989593","title":"Ходячие мертвецы. Том 28. Верная смерть","author":"Роберт Киркман,Чарли Адлард","type":"Комикс","cover":"https://s1.livelib.ru/boocover/1002873012/140/b430/__Hodyachie_mertvetsy._Tom_28._Vernaya_smert.jpg","isbn":"978-5-91339-699-0","publisher":"Комильфо","pubDate":"2018","language":"Русский","series":"Ходячие мертвецы","genres":["Комиксы","манга","графические романы"],"annotation":"Том 28: Верная смерть - двадцать восьмой том комикса комикса «Ходячие мертвецы». Содержит выпуски 163-168.  Океан мёртвых захлестнул островок жизни, на котором ютились наши герои. Столько голов им уже не порубить. Что же они будут делать с таким количеством голодных трупов на пороге? Найдут способ, как обмануть судьбу, или позволят стихии взять своё?  Название тома говорит само за себя: не все выйдут из этой схватки живыми. Как знать, может, в этот раз Роберт Киркман убьёт кого-то, кого вы уже успели полюбить?","acquired":"","cost":null,"sold":false,"soldDate":"","soldPrice":null,"quotes":[],"status":"Прочитал","read":"2021-11","rating":5,"review":"","added":9999763,"hdCover":""},{"id":"0989592","title":"Ходячие мертвецы. Том 27. Война шепчущихся","author":"Роберт Киркман,Клифф Ратбёрн,Стефано Гаудиано,Чарли Адлард","type":"Комикс","cover":"https://s1.livelib.ru/boocover/1002853094/140/072d/__Hodyachie_mertvetsy._Tom_27._Vojna_shepchuschihsya.jpg","isbn":"978-5-91339-681-5","publisher":"Комильфо","pubDate":"2018","language":"Русский","series":"Ходячие мертвецы","genres":["Комиксы","манга","графические романы"],"annotation":"Какие вы знаете стихийные бедствия? Наводнение, землетрясение, пожар, оползень... Нашествие стада мёртвых?.. А если в добавок ко всему направление этому стаду задают \"\"плохие парни\"\"? Тут нужна полная мобилизация и продуманная тактика. Только война покажет, как хорошо сумели подготовиться наши герои и заслужили ли они право на жизнь. В разгар сражения на сторону Рика встаёт неожиданный союзник, но так ли чисты его помыслы?","acquired":"","cost":null,"sold":false,"soldDate":"","soldPrice":null,"quotes":[],"status":"Прочитал","read":"2021-11","rating":5,"review":"","added":9999762,"hdCover":""},{"id":"0989591","title":"Ходячие мертвецы. Том 26. Призыв к оружию","author":"Роберт Киркман","type":"Комикс","cover":"https://s1.livelib.ru/boocover/1002846883/140/0c8b/Robert_Kirkman__Hodyachie_mertvetsy._Tom_26._Prizyv_k_oruzhiyu.jpg","isbn":"978-5-91339-676-1","publisher":"Комильфо","pubDate":"2018","language":"Русский","series":"","genres":["Комиксы","манга","графические романы"],"annotation":"Том 26: Призыв к оружию - двадцать шестой том комикса «Ходячие мертвецы». Содержит выпуски 151-156.  Как давно наши герои сражались? Прошли годы, кто-то потерял сноровку, кто-то привык к безопасности, но вот уже снова настало время брать в руки оружие и биться за свои жизни. В суматохе сборов они упускают из внимания одну очень важную, не такую уж и маленькую деталь, которая может стоить им целой войны. Но и без этого задача предстоит не из лёгких: как сражаться с людьми, у которых в подчинении целые полчища мёртвых?","acquired":"","cost":null,"sold":false,"soldDate":"","soldPrice":null,"quotes":[],"status":"Прочитал","read":"2021-11","rating":5,"review":"","added":9999761,"hdCover":""},{"id":"0989590","title":"Ходячие мертвецы. Том 25. Ни шагу назад","author":"Роберт Киркман","type":"Комикс","cover":"https://s1.livelib.ru/boocover/1001493360/140/9a92/Robert_Kirkman__Hodyachie_mertvetsy._Tom_25._Ni_shagu_nazad.jpg","isbn":"978-5-91339-668-6","publisher":"Комильфо","pubDate":"2018","language":"Русский","series":"","genres":["Комиксы","манга","графические романы"],"annotation":"Долгожданная ярмарка не прошла без следа: потерявшие бдительность герои впустили в дом врага, и тот нанёс страшный удар по сообществам. Внезапные смерти повергли в ужас многих жителей, и Рику придётся проделать огромную работу, чтобы восстановить свой авторитет. Обезумев от горя, люди жаждут крови, и есть только один человек, к которому Рик может обратиться в этой ситуации...","acquired":"","cost":null,"sold":false,"soldDate":"","soldPrice":null,"quotes":[],"status":"Прочитал","read":"2021-11","rating":5,"review":"","added":9999760,"hdCover":""}]');

INSERT OR IGNORE INTO library_items (
  id,title,author,item_type,reading_status,cover_url,hd_cover_url,isbn,publisher,
  publication_date,language,series,genres,annotation,read_date,rating,review,quotes,
  acquired_on,purchase_cost_cents,is_sold,sold_on,sale_price_cents,added
)
SELECT
  json_extract(value,'$.id'),json_extract(value,'$.title'),json_extract(value,'$.author'),
  json_extract(value,'$.type'),json_extract(value,'$.status'),json_extract(value,'$.cover'),
  json_extract(value,'$.hdCover'),json_extract(value,'$.isbn'),json_extract(value,'$.publisher'),
  json_extract(value,'$.pubDate'),json_extract(value,'$.language'),json_extract(value,'$.series'),
  json_extract(value,'$.genres'),json_extract(value,'$.annotation'),json_extract(value,'$.read'),
  json_extract(value,'$.rating'),json_extract(value,'$.review'),json_extract(value,'$.quotes'),
  json_extract(value,'$.acquired'),CASE WHEN json_extract(value,'$.cost') IS NULL THEN NULL ELSE round(json_extract(value,'$.cost')*100) END,
  CASE WHEN json_extract(value,'$.sold') THEN 1 ELSE 0 END,json_extract(value,'$.soldDate'),
  CASE WHEN json_extract(value,'$.soldPrice') IS NULL THEN NULL ELSE round(json_extract(value,'$.soldPrice')*100) END,
  json_extract(value,'$.added')
FROM json_each('[{"id":"098958f","title":"Ходячие мертвецы. Том 24. Жизнь и смерть","author":"Роберт Киркман,Клифф Ратбёрн,Стефано Гаудиано,Чарли Адлард","type":"Комикс","cover":"https://s1.livelib.ru/boocover/1002804502/140/a23c/__Hodyachie_mertvetsy._Tom_24._Zhizn_i_smert.jpg","isbn":"978-5-91339-658-7","publisher":"Комильфо","pubDate":"2018","language":"Русский","series":"Ходячие мертвецы","genres":["Комиксы","манга","графические романы"],"annotation":"Мир, который мы знали, исчез. На смену миру торговли и пустого потребительства пришёл мир выживания и ответственности. Эпидемия апокалиптических масштабов прокатилась по планете, пробудив мёртвых, которые начали пожирать живых. За несколько месяцев человеческое общество было разрушено. исчезли правительства, магазины, доставка почты, кабельное телевидение. В мире, где правят мёртвые, мы наконец вынуждены начать жить.","acquired":"","cost":null,"sold":false,"soldDate":"","soldPrice":null,"quotes":[],"status":"Прочитал","read":"2021-11","rating":5,"review":"","added":9999759,"hdCover":""},{"id":"098958e","title":"Шоу уродов господина Араси","author":"Маруо Суэхиро","type":"Комикс","cover":"https://s1.livelib.ru/boocover/1006801843/140/0c9d/Maruo_Suehiro__Shou_urodov_gospodina_Arasi.jpg","isbn":"978-5-7584-0584-0","publisher":"Фабрика комиксов","pubDate":"2021","language":"Русский","series":"","genres":["Комиксы","манга","графические романы"],"annotation":"Недавно мне исполнилось двенадцать лет. Три года назад от нас с мамой ушёл отец, и мы стали жить одни. Когда мама умерла, я не знала, что мне делать. Хозяин странствующего цирка, вскружив мне голову красивыми словами, уговорил поступить в его труппу. Но вместо рая я попала в ад. Жизнь циркачки так тяжела, что я всерьёз помышляю о самоубийстве. Я не сплю ночами, не хожу в школу и не знаю, что со мной будет на следующий день. Я вся извелась от страха и неопределённости. Как мне быть? Что делать? Знаменитый японский график Суэхиро Маруо представляет на суд читателя трагическую историю юной сиротки Мидори Цубаки, попытавшейся вырваться из уродливого мира цирковых иллюзий в не менее уродливый реальный мир. Перед прочтением я представлял себе нечто схожее с работами Дзюндзи Ито, фактически это и получил. Манга повествует о типичной и бытовой для низших слоёв населения истории: маленькая девочка остаётся одной после смерти матери и ухода отца из семьи, к сожалению, а для девочки поначалу, к счастью, её подбирает передвижной цирк, работники которого, а также выступающие – это люди физически и морально травмированные, с нарушенной психикой и представлениями о нормальной жизни, в общем, такие же сироты, оставленные выживать в суровом мире. Склонность к насилию привычно для циркачей, многолетние обиды, наносимые им, привели к садистским побуждениям по отношению к окружающим. Поэтому маленькая девочка Мидори Цубаки угодила в ловушку, выбраться из которой любой ценой или остаться в цирке навсегда предстоит героине. Изуродованные артисты и директор цирка выступают антагонистами в произведении, противостоять которым придётся двенадцатилетней девочке. Стиль повествования Суэхиро Маруо действительно схож с небезызвестным  автором – Дзюндзи Ито, их роднит как сюжетная целостность с заходами на паранормальные явления, так и искажения обличий людей. Оба автора прекрасно воплощают данные задачи. Но что же всё-таки их отличает? Прочитав историю Маруо, я с уверенностью могу сказать, что рассказы Ито обладают большим проникновением в суть человеческого бытия и поступков людей, нежели это было продемонстрировано в данной манге. Нельзя сказать, что все истории Ито обладают философской мыслью о ценности жизни, но на конкретном примере Маруо демонстрирует слабую работу над оценкой поступков и характеров персонажей, отбросив ненормальных циркачей, говоря о девочке и её \"защитнике\" – Вандере Масамицу. Герои совершают поступки молниеносно, читатель успевает лишь сладить за происходящим, когда в рассказах Ито уделяется время на некое отступление от сюжета, в котором герой раздумывает о своём положении и путях выхода из него. В остальном же – события развиваются быстро, но не сказать чтобы сумбурно, читать и следить за развитием сюжета приятно, в общем, хорошее времяпрепровождение на час обеспечено. Рисунок Маруо в действительности схож с артом Ито, оба мангаки хорошо передают эмоции \"карикатурных лиц\", изгибы мрака и изуродованные части тел персонажей, наводя отвращение к ним. И в заключение, хотелось бы отметить, да, это не прорывная работа, от которой я был в восторге, но крепкая история, способная в некоторых местах удивить и порадовать, а если вы не читали ничего подобного в хоррор жанре и готовы к подобным ужасам, то «Шоу уродов господина Араси» ждёт вас! Еженедельное обсуждение прочитанного в группе ВК.                                                Свернуть","acquired":"","cost":null,"sold":false,"soldDate":"","soldPrice":null,"quotes":[],"status":"Прочитал","read":"2021-11","rating":4,"review":"","added":9999758,"hdCover":""}]');

INSERT OR IGNORE INTO library_items (
  id,title,author,item_type,reading_status,cover_url,hd_cover_url,isbn,publisher,
  publication_date,language,series,genres,annotation,read_date,rating,review,quotes,
  acquired_on,purchase_cost_cents,is_sold,sold_on,sale_price_cents,added
)
SELECT
  json_extract(value,'$.id'),json_extract(value,'$.title'),json_extract(value,'$.author'),
  json_extract(value,'$.type'),json_extract(value,'$.status'),json_extract(value,'$.cover'),
  json_extract(value,'$.hdCover'),json_extract(value,'$.isbn'),json_extract(value,'$.publisher'),
  json_extract(value,'$.pubDate'),json_extract(value,'$.language'),json_extract(value,'$.series'),
  json_extract(value,'$.genres'),json_extract(value,'$.annotation'),json_extract(value,'$.read'),
  json_extract(value,'$.rating'),json_extract(value,'$.review'),json_extract(value,'$.quotes'),
  json_extract(value,'$.acquired'),CASE WHEN json_extract(value,'$.cost') IS NULL THEN NULL ELSE round(json_extract(value,'$.cost')*100) END,
  CASE WHEN json_extract(value,'$.sold') THEN 1 ELSE 0 END,json_extract(value,'$.soldDate'),
  CASE WHEN json_extract(value,'$.soldPrice') IS NULL THEN NULL ELSE round(json_extract(value,'$.soldPrice')*100) END,
  json_extract(value,'$.added')
FROM json_each('[{"id":"098958d","title":"Дикая Планета","author":"Дзиро Мацумото","type":"Комикс","cover":"https://s1.livelib.ru/boocover/1001478032/140/a546/Dziro_Matsumoto__Dikaya_Planeta.jpg","isbn":"978-5-905295-26-3","publisher":"Alt Graph","pubDate":"2015","language":"Русский","series":"","genres":["Комиксы","манга","графические романы"],"annotation":"Осаждённый город на безымянном фронте большой войны — недружелюбная декорация жизни трёх молодых людей, брошенных в холодные будни взрослой жизни. Они ещё хранят тепло детских сердец и мечты о будущем. Но экипаж подбитого космического корабля вынужден терпеть жестокую реальность дикой планеты.  Застывшие на позициях оккупационные войска срослись с городской мафией и задают привычный ритм городской жизни. Среди нужды и беззакония неунывающая и трудолюбивая продавщица хлеба Наоми, подающий надежды художник Коро и самовлюблённая танцовщица Кукки ищут способы наполнить прохудившиеся топливные баки, чтобы оживить спасительный механизм ракеты. Они верят, что ракета способна вырвать их из безнадёжной повседневности гибнущего города.  Три дороги между реальностью и вымыслом сквозь ядовитые капканы ошибок и зыбкие пески авантюр ведут героев к общей цели, лежащей за пределами Млечного Пути. Покупая мангу, я не обращал внимание ни на представленное описание, ни на рецензии и иллюстрации. Перед прочтением я ознакомился с аннотацией, вообразив какую-то \"постапокалиптическую\" историю и изменившийся до неузнаваемости мир после крушения ракеты. Те, кто слышал о манге или читал её, должны понять меня, буквально открыв мангу, я был, мягко сказать, удивлён. Это именно тот случай, когда 18+ рейтинг оправдан в полной мере: обилие секса, насилия, выраженного как в ментальном, так и в физическом воплощении, человеческой жестокости и глупых предрассудков. Манга оказалась совершенно разносторонней, но с явно прослеживающейся моралью о сохранении самобытности собственной мысли, несмотря на тяготы жизни, выраженной в окружающей тебя обстановке, что при любых обстоятельствах ты должен сохранять позитивный настрой и держать ухо востро. Первые 90 страниц выглядят так, как будто ты читаешь жёсткий бдсм-фанфик в безумном мире («Безумный Макс» близок к манге), по другому сложно описать происходящее. Позже, с каждой страницей сюжет начинает набирать обороты и выстраиваться в единое целое и взаимосвязанное произведение. Именно 2/3 манги заставляют прочувствовать спектр эмоций: от самых сильных переживаний за жизнь героев до тоски и грусти по тем «беззаботным» временам и пережитком прошлого, когда жизнь героев каждый день дробилась на до и после. Три разных героя, дружившие и близко общающиеся, но некогда рассорившиеся и возненавидевшие друг друга из-за окружающих их обстоятельств и ежедневных угроз. У каждого из них тяжёлая судьба и не менее лёгкое будущее, каждый персонаж осознаёт со временем о принципах выживания, кто-то раньше, способствуя получению привилегий в обществе, а кто-то позже, осознавая суровую истину, лежащую на поверхности. Человеческая глупость, простота и непреднамеренная жестокость могут погубить тебя и твоих знакомых, манга прекрасно иллюстрирует данные происшествия. Это философское произведение, прочтя которое, будет неправильным называть его чрезмерно надменным, ведь, если задуматься, то творящийся беспредел, как минимум, происходил в нашем мире, но большая часть социума смогла перейти на следующий этап, оставив \"первобытные\" представления позади. Упавшая ракета выполняет сразу несколько функций изображения: во-первых, наиболее прослеживающееся – это способ человека уйти от проблем настоящего и заставить себя забыть о них. Данное явление автор порицает, изменяя характер персонажа по ходу сюжета. Но история, придуманная Коро помогает ему жить и сохранять наивный оптимизм, наряду с художеством. Коро продолжает быть верен в свой вымысел о спасательной капсуле до одного ракового момента, ранее заражая оптимизмом своих друзей. Во-вторых, падение ракеты служит камнем преткновения в истории, жители не говорят о случавшихся ранее событиях, упоминая лишь разбитый корабль, напоминающий им о прошлом. Странное явление, показывающее \"ничтожность\" жизни людей в данном городе/ стране/ планете, когда кусок металлолома, свалившийся с неба, диктует условия оставшегося времени. Суровый мир войны и беззакония проливает свет на совершенно непримечательный клочок земли под названием «Дикая планета», оказавшаяся действительно такой. Это не заросшие джунгли и труднопроходимые тропики с кучей убийственных ловушек природы. Это реальность социума, построенная из голов и вымощенная из костей других людей, где привычная ярость и дикость животных обретает иной контраст, отражающийся на низменных потребностях людей. Трагедия, обличающая пороки общества и чётко определяющая их вычурность и тлетворность при бездействии. Гротескный рисунок и преобладание непроглядно чёрного цвета погружают ещё больше в историю, а проработка отдельных элементов и лиц персонажей радует такой особенностью. Хорошая история Дзиро Мацумото, запоминающаяся в первую очередь своим пугающим изображением привычного, а позже погружающее тебя в мир человеческого разума и заставляющее задуматься. Еженедельное обсуждение прочитанного в группе ВК.                                                Свернуть","acquired":"","cost":null,"sold":false,"soldDate":"","soldPrice":null,"quotes":[],"status":"Прочитал","read":"2021-11","rating":4,"review":"","added":9999757,"hdCover":""},{"id":"098958c","title":"Ходячие мертвецы. Том 23. Шёпот, переходящий в крик. Выпуск 134","author":"Роберт Киркман","type":"Книга","cover":"https://s1.livelib.ru/boocover/1001102878/140/7e90/Robert_Kirkman__Hodyachie_mertvetsy._Tom_23._Shjopot_perehodyaschij_v_krik._Vypu.jpg","isbn":"","publisher":"","pubDate":"2014","language":"Русский","series":"","genres":[],"annotation":"Иисусу удается отбиться от мертвецов и тех, кто себя за них выдает. Он спасает раненного напарника, более того Иисусу удается даже обезвредить и пленить предводительницу \"говорящих мертвецов\", после чего он, вместе с раненным и пленницей отправляется назад в Хиллтоп.  А в это время в Хиллтопе на уединившихся Карла и Софию нападают двое хулиганов, они избивают Карла, а затем начинают издеваться над Софией, мстя ей за её заступничество за Брайна. Неожиданно Карл набрасывается на хулиганов и избивает обоих лопатой, очень может быть что насмерть.  Иисус приезжает в Хиллтоп. Раненый отправляется на лечение, пленница на допрос, но Иисус и Мегги не успевают ничего узнать. Появившиеся Карл и София рассказывают им о случившемся с ними","acquired":"","cost":null,"sold":false,"soldDate":"","soldPrice":null,"quotes":[],"status":"Прочитал","read":"2021-11","rating":5,"review":"","added":9999756,"hdCover":""}]');
